CREATE TABLE "Users" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Username" text NOT NULL,
    "Email" text NOT NULL,
    "PasswordHash" text NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Users" PRIMARY KEY ("Id")
);

CREATE TABLE "Boards" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" text NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "OwnerId" integer NOT NULL,
    CONSTRAINT "PK_Boards" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Boards_Users_OwnerId" FOREIGN KEY ("OwnerId") REFERENCES "Users" ("Id") ON DELETE CASCADE
);

CREATE TABLE "BoardMembers" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "JoinedAt" timestamp with time zone NOT NULL,
    "Role" text NOT NULL,
    "UserId" integer NOT NULL,
    "BoardId" integer NOT NULL,
    CONSTRAINT "PK_BoardMembers" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_BoardMembers_Boards_BoardId" FOREIGN KEY ("BoardId") REFERENCES "Boards" ("Id"),
    CONSTRAINT "FK_BoardMembers_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
);

CREATE TABLE "Columns" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" text NOT NULL,
    "Order" integer NOT NULL,
    "BoardId" integer NOT NULL,
