    CONSTRAINT "FK_Columns_Boards_BoardId" FOREIGN KEY ("BoardId") REFERENCES "Boards" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TaskCards" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
