    CONSTRAINT "PK_TaskCards" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TaskCards_Columns_ColumnId" FOREIGN KEY ("ColumnId") REFERENCES "Columns" ("Id") ON DELETE CASCADE
);

